import { useContext } from 'react';
import { overlayHub } from '@arvo/core';
import type { OverlayEntry } from '@arvo/core';
import { OverlayContext } from '../providers/OverlayContext';

export interface UseOverlayReturn {
  open: (entry: OverlayEntry) => void;
  close: (id: string) => void;
  closeAll: (options?: { except?: string[] }) => void;
  isOpen: (id: string) => boolean;
  getContainer: () => HTMLElement;
}

export function useOverlay(): UseOverlayReturn {
  // Fall back to the module-level singleton when no OverlayProvider is mounted.
  // This allows Popover (and other overlay components) to work in Storybook,
  // tests, or any context that omits <OverlayProvider>.
  const hub = useContext(OverlayContext) ?? overlayHub;
  return {
    open: (entry) => hub.open(entry),
    close: (id) => hub.close(id),
    closeAll: (opts) => hub.closeAll(opts),
    isOpen: (id) => hub.isOpen(id),
    getContainer: () => hub.getContainer(),
  };
}
